options.css:
@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@600;700;800;900&display=swap');

:root{
  --ct-accent: #58a6ff;
  --ct-accent2:#7dc4ff;

  --ct-ok:#22c55e;
  --ct-bad:#ff5c5c;
  --ct-warn:#f6c445;

  --ct-text:#eaf3ff;

  --ct-panel-border: rgba(88,166,255,0.22);
  --ct-panel-topglow: rgba(10,20,36,0.92);
  --ct-panel-bg1: rgba(18,36,60,0.88);
  --ct-panel-bg2: rgba(10,20,36,0.92);
  --ct-soft-line: rgba(255,255,255,0.08);
  --ct-card-bg: rgba(10,20,36,0.92);
  --ct-input-bg: rgba(10,18,30,0.82);
}

.ct-layout{
  height:100%;
  display:grid;
  grid-template-columns: 2.05fr 1fr;
  gap: 12px;
  font-family:"Segoe UI",system-ui,sans-serif;
  color: var(--ct-text);
}

.kpi-main,
.readout-main{
  font-weight: 900;
  letter-spacing: 0.5px;
}

/* shared panel look */
.panel{
  border-radius: 14px;
  border: 1px solid var(--ct-panel-border);
  background: linear-gradient(180deg, var(--ct-panel-bg1), var(--ct-panel-bg2)),
              radial-gradient(circle at top, rgba(88,166,255,0.05), transparent 70%);
  box-shadow: 0 12px 26px rgba(0,0,0,0.45), inset 0 0 0 1px rgba(125,196,255,0.05);
  padding: 12px;
  overflow:hidden;
  position: relative;
}

.panel:before{
  content:"";
  position:absolute;
  left:10px; right:10px; top:0;
  height:2px;
  background: linear-gradient(90deg, transparent, var(--ct-panel-topglow), transparent);
  opacity:0.75;
}

.ct-left{ height:100%; }
.ct-right{ height:100%; display:flex; flex-direction:column; gap: 12px; }

.ct-detail-header{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:10px;
}

.ct-detail-title{
  font-size: 26px;
  font-weight: 900;
  letter-spacing: 1.6px;
  text-transform: uppercase;
  text-shadow: 0 0 12px rgba(88,166,255,0.18);
}

.ct-detail-chip{
  display:flex;
  align-items:center;
  gap:10px;
  padding:8px 12px;
  border-radius: 12px;
  border: 1px solid rgba(88,166,255,0.26);
  background: linear-gradient(180deg, rgba(18,32,52,0.92), rgba(9,16,28,0.92));
}

.chip-label{
  font-weight:900;
  opacity:0.85;
  letter-spacing:1px;
  font-size:12px;
  color:#d8e8ff;
}

.chip-value{
  font-weight:900;
  font-size:16px;
  padding:4px 10px;
  border-radius: 999px;
  background: rgba(88,166,255,0.14);
  border: 1px solid rgba(88,166,255,0.30);
  color: #ffffff;
}

.ct-detail-grid{
  display:grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
  height: calc(100% - 58px);
}

.panel-title{
  font-weight: 900;
  letter-spacing: 1px;
  text-transform: uppercase;
  font-size: 12px;
  opacity: 0.95;
  margin-bottom: 10px;
  color:#d9e9ff;
}

/* TANK PANEL */
.tank-panel{
  display:flex;
  flex-direction:column;
  gap: 10px;
  height:100%;
  position: relative;
  border-radius: 12px;
  background:
    radial-gradient(circle at 45% 25%, rgba(88,166,255,0.05), transparent 70%),
    linear-gradient(180deg, rgba(10,18,30,0.96), rgba(2,8,16,0.99));
}

.tank-hero{
  display:flex;
  justify-content:center;
  align-items:flex-start;
  padding-top: 4px;
  margin-bottom: -6px;
}

.tank-pack{
  display:flex;
  justify-content:center;
  align-items:flex-start;
  gap: 12px;
  margin: 0 auto;
}

.tank-scale.big{
  position:relative;
  height: 175px;
  width: 48px;
  font-size: 12px;
  color: rgb(210, 225, 245);
}

.tank-scale.big .tick{ position:absolute; left:0; }
.tank-scale.big .tick-top{ top:0; }
.tank-scale.big .tick-mid{ top:50%; transform:translateY(-50%); }
.tank-scale.big .tick-bottom{ bottom:0; }

.tank-body.big{
  display:flex;
  flex-direction:column;
  align-items:center;
}

.tank-outer.big{
  position:relative;
  width: 135px;
  height: 195px;
}

.tank-inner.big{
  position:absolute;
  left:0; right:0; top:0; bottom:16px;
  margin:auto;
  border-radius: 16px;
  border: 2px solid rgba(255,255,255,0.82);
  background: radial-gradient(circle at 30% 0%, #203553 0, #0f1d31 62%, #09111b 100%);
  overflow:hidden;
  box-shadow: 0 0 10px rgba(0,0,0,0.65), inset 0 0 14px rgba(0,0,0,0.85), 0 0 18px rgba(88,166,255,0.12);
}

.tank-glass{
  position:absolute;
  top:4%; bottom:45%; left:10%;
  width:20%;
  border-radius:50px;
  background: linear-gradient(to bottom, rgba(255,255,255,0.20), rgba(255,255,255,0));
}

.tank-band{
  position:absolute;
  left:0; right:0;
  bottom:24%;
  height:12%;
  background: rgba(88,166,255,0.10);
}

.tank-fill{
  position:absolute;
  left:0; right:0; bottom:0;
  height:45%;
  background: linear-gradient(to top, #2d6cdf, #58a6ff 55%, #cfe7ff 100%);
  box-shadow: 0 0 14px rgba(88,166,255,0.35), inset 0 3px 10px rgba(255,255,255,0.16);
}

.tank-fill.level-green{ background: linear-gradient(to top, #118b43, #22c55e 45%, #bbf7d0 100%); }
.tank-fill.level-yellow{ background: linear-gradient(to top, #b88900, #f6c445 55%, #fff1b3 100%); }
.tank-fill.level-red{ background: linear-gradient(to top, #9f1f1f, #ff5c5c 50%, #ffd4d4 100%); }

.tank-foot{
  position:absolute;
  bottom:0;
  width:16px;
  height:10px;
  background: linear-gradient(to top, #62758d, #9aabbe);
  border-radius: 4px 4px 0 0;
  box-shadow: 0 0 6px rgba(0,0,0,0.65);
}

.tank-foot.left{ left: 16px; }
.tank-foot.right{ right: 16px; }

.tank-zone{
  position:absolute;
  left:12px;
  font-size: 10px;
  font-weight: 900;
  letter-spacing: 1px;
  opacity: 0.72;
  color:#edf5ff;
}

.tank-zone.top{ top: 10px; }
.tank-zone.mid{ top: 48%; transform: translateY(-50%); }
.tank-zone.low{ bottom: 24px; }

.tank-readout{
  margin-top: 6px;
  text-align:center;
}

.readout-main{
  font-size: 34px;
  font-weight: 900;
  letter-spacing: 0.6px;
  color:#ffffff;
}

.readout-unit{
  font-size: 14px;
  font-weight: 900;
  opacity:0.85;
  margin-left:6px;
  color:#d8e8ff;
}

.ct-last-update{
  margin-top:10px;
  padding:6px 10px;
  border-radius:999px;
  border:1px solid rgba(88,166,255,.22);
  background: rgba(9,18,30,.70);
  font-size:11px;
  font-weight:900;
  letter-spacing:.8px;
  color:#d8e8ff;
}

.ct-last-update b{
  color:#ffffff;
  margin-left:8px;
}

/* KPI PANEL */
.kpi-panel{
  display:flex;
  flex-direction:column;
  height:100%;
  position: relative;
  border-radius: 12px;
  background:
    radial-gradient(circle at 45% 25%, rgba(88,166,255,0.05), transparent 70%),
    linear-gradient(180deg, rgba(10,18,30,0.96), rgba(2,8,16,0.99));
}

.kpi-grid{
  display:grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
  align-content:start;
}

.kpi-card{
  border-radius: 14px;
  border: 1px solid rgba(88,166,255,0.14);
  background: var(--ct-card-bg);
  padding: 10px;
  box-shadow: inset 0 0 0 1px rgba(125,196,255,0.04);
}

.kpi-card.kpi-green{
  border: 1px solid rgba(0,255,120,.38);
  background:
    linear-gradient(135deg, rgba(0,255,120,.16) 0%, rgba(0,255,120,.06) 22%, rgba(4,18,14,.92) 100%);
  box-shadow:
    inset 0 0 0 1px rgba(0,255,120,.06),
    inset 0 0 28px rgba(0,255,120,.08),
    0 0 14px rgba(0,255,120,.06);
}

.kpi-card.kpi-green .kpi-label{
  color:#00ff7a;
  text-shadow: 0 0 6px rgba(0,255,120,.22);
}

.kpi-card.kpi-green .kpi-main,
.kpi-card.kpi-green .kpi-value,
.kpi-card.kpi-green .kpi-unit{
  color:#ecfff4;
}

.kpi-card.kpi-red{
  border: 1px solid rgba(255,77,77,.38);
  background:
    linear-gradient(135deg, rgba(255,77,77,.16) 0%, rgba(255,77,77,.06) 22%, rgba(20,8,8,.92) 100%);
  box-shadow:
    inset 0 0 0 1px rgba(255,77,77,.06),
    inset 0 0 28px rgba(255,77,77,.08),
    0 0 14px rgba(255,77,77,.06);
}

.kpi-card.kpi-red .kpi-label{
  color:#ff5c5c;
  text-shadow: 0 0 6px rgba(255,92,92,.22);
}

.kpi-card.kpi-red .kpi-main,
.kpi-card.kpi-red .kpi-value,
.kpi-card.kpi-red .kpi-unit{
  color:#fff0f0;
}

.kpi-card.kpi-grey{
  border: 1px solid rgba(132,128,128,0.38);
  background:
    linear-gradient(135deg, rgba(132,128,128,0.22) 0%, rgba(132,128,128,0.08) 22%, rgba(20,20,24,.92) 100%);
  box-shadow:
    inset 0 0 0 1px rgba(132,128,128,.06),
    inset 0 0 28px rgba(132,128,128,.06),
    0 0 14px rgba(132,128,128,.04);
}

.kpi-label{
  font-size: 11px;
  font-weight: 900;
  text-transform: uppercase;
  letter-spacing: 1px;
  color:#d9e9ff;
}

.kpi-main{
  margin-top: 6px;
  font-size: 24px;
  font-weight: 900;
  color:#ffffff;
}

.kpi-unit{
  font-size: 12px;
  font-weight: 900;
  opacity:0.8;
  margin-left:6px;
  color:#d9e9ff;
}

.mini-trend{
  margin-top: 10px;
  padding: 10px;
  border: 1px solid rgba(20,45,85,0.9);
  border-radius: 12px;
  background: rgba(6,14,26,0.35);
}

.mini-title{
  display:flex;
  justify-content:space-between;
  align-items:center;
  font-size: 11px;
  font-weight: 900;
  letter-spacing: 1px;
  text-transform: uppercase;
  color:#d9e9ff;
  margin-bottom: 8px;
}

.mini-last{
  font-size: 11px;
  font-weight: 900;
  color: rgba(210,225,245,0.85);
  text-transform:none;
}

.mini-chart{
  height: 150px;
  border-radius: 12px;
  border: 1px solid rgba(30,60,110,0.75);
  background: rgba(8,16,28,0.92);
  overflow: hidden;
  position: relative;
}

/* KPI STATUS */
.val-ok{
  color:#22c55e !important;
  text-shadow:0 0 8px rgba(34,197,94,.25);
  font-weight:900;
}

.val-bad{
  color:#ff5c5c !important;
  text-shadow:0 0 8px rgba(255,92,92,.25);
  font-weight:900;
}

@keyframes kpiBlink{
  0%,100%{ opacity:1; }
  50%{ opacity:0.25; }
}

.blink{
  animation:kpiBlink 0.8s infinite;
}

/* RIGHT SIDE */
.pcd-head{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:12px;
  margin-bottom:10px;
}

.pcd-head-left{
  position:relative;
  padding-left:14px;
}

.pcd-head-left::before{
  content:"";
  position:absolute;
  left:0; top:3px; bottom:3px;
  width:5px;
  border-radius:999px;
  background: linear-gradient(180deg, rgba(88,166,255,.96), rgba(125,196,255,.90));
}

.pcd-title{
  font-size:18px;
  font-weight:1000;
  letter-spacing:1.2px;
  text-transform:uppercase;
}

.pcd-search{
  display:flex;
  align-items:center;
  gap:8px;
  border:1px solid rgba(255,255,255,.10);
  background: var(--ct-input-bg);
  border-radius:12px;
  padding:9px 12px;
  min-width: 280px;
}

.pcd-search-in{
  width:100%;
  border:0;
  outline:none;
  background: transparent;
  color:#ECF6FF;
  font-size:13px;
}

.pcd-search-ic{
  opacity:.75;
  font-weight:1000;
}

.pcd-table-wrap{
  border:1px solid rgba(255,255,255,.08);
  background: rgba(8,14,24,.62);
  border-radius:14px;
  overflow:hidden;
  height: 46%;
  display:flex;
  flex-direction:column;
  overflow-y:auto;
}

.pcd-table-head{
  font-size:12px;
  opacity:.82;
  letter-spacing:.8px;
  font-weight:1000;
  text-transform:uppercase;
  background: linear-gradient(180deg, rgba(255,255,255,.06), rgba(255,255,255,.02));
  border-bottom:1px solid rgba(255,255,255,.10);
  position: sticky;
  top: 0;
  z-index: 2;
}

.pcd-row{
  display:grid;
  grid-template-columns: 1.05fr 1.0fr 1.2fr 1.0fr .6fr .45fr .55fr .55fr .55fr .7fr;
  gap:12px;
  align-items:center;
  padding:14px 14px;
  font-size:13px;
}

.pcd-item{
  border-bottom:1px solid rgba(255,255,255,.06);
  background: rgba(255,255,255,.01);
  position:relative;
}

.pcd-item:last-child{
  border-bottom:0;
}

.pcd-item::before{
  content:"";
  position:absolute;
  left:0; top:0; bottom:0;
  width:4px;
  background: rgba(88,166,255,.85);
}

.pcd-strong{
  font-weight:1000;
  color:#fff;
}

.pcd-dim{
  opacity:.82;
}

.pcd-chipval{
  display:inline-block;
  padding:8px 12px;
  border-radius:999px;
  font-weight:1000;
  font-size:12px;
  color:#eef6ff;
  background: rgba(88,166,255,.12);
  border:1px solid rgba(88,166,255,.22);
}

.pcd-chipval.ph{
  background: rgba(125,196,255,.12);
  border-color: rgba(125,196,255,.24);
}

.pcd-state-btn{
  cursor:pointer;
  display:inline-flex;
  align-items:center;
  justify-content:center;
  padding:8px 14px;
  border-radius:999px;
  font-size:12px;
  font-weight:1000;
  letter-spacing:.7px;
  border:1px solid rgba(255,255,255,.12);
  background: rgba(255,255,255,.06);
  color:#ECF6FF;
}

.pcd-state-btn.running{
  color: #58a6ff;
  background: rgba(88,166,255,.14);
  border-color: rgba(88,166,255,.32);
  box-shadow: inset 0 0 10px rgba(88,166,255,.08);
}

.pcd-state-btn.completed{
  color: #22c55e;
  background: rgba(34,197,94,.12);
  border-color: rgba(34,197,94,.28);
  box-shadow: inset 0 0 10px rgba(34,197,94,.06);
}

.pcd-state-btn.is-selected{
  box-shadow: 0 0 0 2px rgba(255,255,255,.10), 0 10px 22px rgba(0,0,0,.35);
}

/* ALARM LOG */
.log-card{
  height: calc(54% - 10px);
  border-radius:18px;
  border:1px solid rgba(255,255,255,.10);
  background: rgba(255,255,255,.03);
  box-shadow: 0 16px 38px rgba(0,0,0,.55);
  overflow:hidden;
  display:flex;
  flex-direction:column;
}

.log-top{
  display:flex;
  justify-content:space-between;
  align-items:flex-end;
  gap:12px;
}

.log-titlebox{
  border-left:6px solid rgba(88,166,255,.92);
  padding-left:12px;
}

.log-title{
  font-weight:1000;
  letter-spacing:1px;
}

.log-sub{
  margin-top:3px;
  font-size:12px;
  opacity:.78;
}

.log-actions{
  display:flex;
  align-items:center;
  gap:10px;
}

.log-badge{
  padding:8px 10px;
  border-radius:12px;
  background: rgba(255,255,255,.08);
  border:1px solid rgba(255,255,255,.12);
  font-size:12px;
  font-weight:900;
  letter-spacing:.6px;
}

.log-search{
  display:flex;
  align-items:center;
  gap:8px;
  background: var(--ct-input-bg);
  border:1px solid rgba(255,255,255,.12);
  border-radius:14px;
  padding:10px 12px;
  min-width: 240px;
}

.log-search input{
  width:100%;
  border:0;
  outline:none;
  background:transparent;
  color:#EAF3FF;
  font-size:13px;
}

.log-ic{
  opacity:.8;
  font-weight:900;
}

.log-head{
  display:grid;
  grid-template-columns: 170px 170px 1fr 120px;
  gap:12px;
  padding:14px 16px;
  font-size:12px;
  font-weight:1000;
  letter-spacing:.9px;
  text-transform:uppercase;
  opacity:.85;
  background: rgba(255,255,255,.06);
  border-bottom:1px solid rgba(255,255,255,.10);
}

.log-body{
  overflow-y:auto;
  padding:10px 10px 0;
}

.log-row{
  display:grid;
  grid-template-columns: 170px 170px 1fr 120px;
  gap:12px;
  align-items:center;
  padding:14px 14px;
  margin-bottom:10px;
  border-radius:14px;
  background: rgba(0,0,0,.28);
  border:1px solid rgba(255,255,255,.08);
  position:relative;
}

.log-row::before{
  content:"";
  position:absolute;
  left:0; top:0; bottom:0;
  width:6px;
  border-radius:14px 0 0 14px;
  background: rgba(125,196,255,.80);
}

.log-row.sev-high::before{ background: rgba(255,90,90,.90); }
.log-row.sev-med::before{ background: rgba(246,196,69,.95); }
.log-row.sev-low::before{ background: rgba(34,197,94,.90); }
.log-row.sev-info::before{ background: rgba(125,196,255,.85); }

.log-row.is-active .log-code,
.log-row.is-active .msg-main{
  color:#ff5c5c;
}

.log-row.is-clear .log-code,
.log-row.is-clear .msg-main{
  color:#22c55e;
}

.log-time{
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace;
  letter-spacing:.2px;
}

.log-time .dt{
  font-size:12px;
  opacity:.82;
}

.log-time .tm{
  font-size:18px;
  font-weight:1000;
  margin-top:2px;
}

.log-code{
  font-weight:1000;
  letter-spacing:.6px;
  font-size:13px;
}

.log-msg .msg-main{
  font-size:14px;
  font-weight:900;
}

.log-msg .msg-sub{
  margin-top:3px;
  font-size:12px;
  opacity:.72;
}

.tag{
  display:inline-flex;
  justify-content:center;
  align-items:center;
  padding:8px 12px;
  border-radius:999px;
  font-size:12px;
  font-weight:1000;
  border:1px solid rgba(255,255,255,.10);
  background: rgba(255,255,255,.06);
}

.tag.state.active{
  color:#ff5c5c;
  background: rgba(255,92,92,.14);
  border-color: rgba(255,92,92,.34);
  box-shadow: inset 0 0 10px rgba(255,92,92,.08);
}

.tag.state.clear{
  color:#22c55e;
  background: rgba(34,197,94,.12);
  border-color: rgba(34,197,94,.28);
  box-shadow: inset 0 0 10px rgba(34,197,94,.06);
}

.log-foot{
  margin-top:auto;
  padding:10px 14px;
  display:flex;
  justify-content:space-between;
  align-items:center;
  font-size:12px;
  opacity:.78;
  border-top:1px solid rgba(255,255,255,.08);
  background: rgba(0,0,0,.18);
}

@media (max-width: 1200px){
  .ct-layout{ grid-template-columns: 1fr; }
  .ct-detail-grid{ grid-template-columns: 1fr; height:auto; }
  .pcd-table-wrap{ height: 320px; }
  .log-card{ height: 420px; }
}

.pcd-state-btn {
  position: relative;
  transition: all 0.2s ease;
}

.pcd-state-btn.is-selected {
  border: 2px solid #7dc4ff !important;
  box-shadow:
    0 0 0 2px rgba(125, 196, 255, 0.16),
    0 0 14px rgba(125, 196, 255, 0.24);
  transform: translateY(-1px);
}

.pcd-item:has(.pcd-state-btn.is-selected) {
  border-left: 3px solid #7dc4ff;
  background: linear-gradient(90deg, rgba(125,196,255,0.08), rgba(125,196,255,0.02));
}

/* ================= STANDARDIZED DETAIL DASHBOARD SYSTEM ================= */
.ct-layout{
  --font-ui:"Segoe UI Variable Text","Segoe UI",system-ui,sans-serif;
  --font-display:"Segoe UI Variable Display","Segoe UI",system-ui,sans-serif;
  --font-mono:ui-monospace,SFMono-Regular,Menlo,Consolas,"Liberation Mono",monospace;
  --detail-text:#eaf3ff;
  --detail-muted:#c8d9ee;
  --detail-edge:rgba(35,139,230,.48);
  --detail-edge-soft:rgba(88,166,255,.28);
  --detail-page:oklch(14.5% .016 250);
  --detail-panel-top:oklch(22.5% .032 250);
  --detail-panel-bottom:oklch(18.5% .026 250);
  --detail-content:oklch(17% .020 250);
  --detail-plot:oklch(17.5% .021 250);
  position:relative;
  isolation:isolate;
  min-width:0;
