options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
try {
  const root = htmlNode;
  const seriesList = data?.series || [];
  if (!root) return;

  const renderKey = Date.now() + "_" + Math.random().toString(36).slice(2);
  root.__renderKey = renderKey;

  const safeNum = (v, d = NaN) => {
    const n = Number(v);
    return Number.isFinite(n) ? n : d;
  };

  const safeStr = (v, d = "--") => {
    if (v === null || v === undefined) return d;
    const s = String(v).trim();
    return s ? s : d;
  };

  const setText = (sel, val) => {
    const el = root.querySelector(sel);
    if (el) el.textContent = val;
  };

  function resetDashboardNoData() {
    setText("#cnType", "--");
    setText("#mraType", "--");
    setText("#cnPct", "--");
    setText("#nobelPct", "--");
    setText("#phValue", "--");
    setText("#hzValue", "--");
    setText("#levelCm", "--");

    ["#cnLast", "#nobelLast", "#phLast", "#lvlLast"].forEach(sel => setText(sel, "--"));

    ["#cnChart", "#nobelChart", "#phChart", "#lvlChart"].forEach(sel => {
      const el = root.querySelector(sel);
      if (el) el.innerHTML = "";
    });

    const tankFill = root.querySelector("#tankFill");
    if (tankFill) {
      tankFill.style.height = "0%";
      tankFill.classList.remove("level-green", "level-yellow", "level-red");
    }

    root.querySelectorAll(".kpi-card").forEach(card => {
      card.classList.remove("kpi-green", "kpi-red");
      card.classList.add("kpi-grey");
    });

    setText("#alarmBadge", "0 Active");
    setText("#alarmSub", "No data for selected tank");
    setText("#alarmFootLeft", "Last refresh: --");
  }

  function clearChart(chartSelector, lastSelector) {
    const chart = root.querySelector(chartSelector);
    if (chart) chart.innerHTML = "";
    if (lastSelector) setText(lastSelector, "--");
  }

  function normalizeSeriesData(times, values, lo, hi) {
    const N = Math.min(times.length, values.length, lo.length, hi.length);
    const outT = [];
    const outV = [];
    const outLo = [];
    const outHi = [];

    for (let i = 0; i < N; i++) {
      const t = times[i];
      const v = Number(values[i]);
      const l = Number(lo[i]);
      const h = Number(hi[i]);

      if (!Number.isFinite(new Date(t).getTime())) continue;
      if (!Number.isFinite(v) || !Number.isFinite(l) || !Number.isFinite(h)) continue;

      outT.push(t);
      outV.push(v);
      outLo.push(l);
      outHi.push(h);
    }

    return { times: outT, values: outV, lo: outLo, hi: outHi };
  }

  function getCurrentTank() {
    try {
      const gvNo =
        (typeof replaceVariables === "function" ? replaceVariables("${tankNo}") : "") || "";
      const gvSuffix =
        (typeof replaceVariables === "function" ? replaceVariables("${tankSuffix}") : "") || "";

      const tankNo = String(gvNo).trim();
      const tankSuffix = String(gvSuffix).trim().toUpperCase();

      if (tankNo && tankSuffix) return `${tankNo}${tankSuffix}`;

      const params = new URLSearchParams(window.location.search);
      const urlTankNo = params.get("var-tankNo") || "1";
      const urlTankSuffix = params.get("var-tankSuffix") || "A";
      return `${urlTankNo}${urlTankSuffix}`;
    } catch (e) {
      return "1A";
    }
  }

  const defer = (fn) => {
    const myKey = renderKey;
    setTimeout(() => {
      if (root.__renderKey !== myKey) return;
      fn();
    }, 60);
  };

  const getSeries = (refId) =>
    seriesList.find((s) => String(s.refId).toUpperCase() === String(refId).toUpperCase());

  const getSeriesListByRefId = (refId) =>
    seriesList.filter((s) => String(s.refId).toUpperCase() === String(refId).toUpperCase());

  const getFieldFromSeries = (series, name) => {
    if (!series) return null;
    return (series.fields || []).find(
      (x) => String(x.name).toLowerCase() === String(name).toLowerCase()
    ) || null;
  };

  const getArrayFromField = (field) => {
    if (!field) return [];
    if (field.values?.toArray) return field.values.toArray();
    if (field.values?.buffer) return Array.from(field.values.buffer);
    if (Array.isArray(field.values)) return field.values;
    if (field.values?.get) {
      const arr = [];
      const len = field.values.length ?? 0;
      for (let i = 0; i < len; i++) arr.push(field.values.get(i));
      return arr;
    }
    return [];
  };

  const getFirst = (series, fieldName, fallback) => {
    const f = getFieldFromSeries(series, fieldName);
    if (!f) return fallback;
    const v = f.values?.get ? f.values.get(0) : (f.values?.[0] ?? fallback);
    return v ?? fallback;
  };

  const getLabelValue = (series, key, fallback = "--") => {
    if (!series?.fields) return fallback;

    const fld = (series.fields || []).find(
      (f) => String(f.name).toLowerCase() === String(key).toLowerCase()
    );
    if (fld) {
      const v = fld.values?.get ? fld.values.get(0) : (fld.values?.[0] ?? fallback);
      if (v !== undefined && v !== null && String(v).trim() !== "") return v;
    }

    for (const f of series.fields || []) {
      if (f.labels) {
        for (const [k, v] of Object.entries(f.labels)) {
          if (String(k).toLowerCase() === String(key).toLowerCase()) {
            if (v !== undefined && v !== null && String(v).trim() !== "") return v;
          }
        }
      }
    }

    if (series.name && typeof series.name === "string") {
      const m = series.name.match(new RegExp(`${key}=([^,} ]+)`, "i"));
      if (m && m[1]) return m[1];
    }

    return fallback;
  };

  const pickTimeField = (series) => {
    if (!series?.fields) return null;

    let f = series.fields.find((x) => String(x.name).toLowerCase() === "_time");
    if (f) return f;

    f = series.fields.find((x) => String(x.name).toLowerCase() === "time");
    if (f) return f;

    f = series.fields.find((x) => x.type === "time");
    if (f) return f;

    return (
      series.fields.find((x) => {
        const arr = getArrayFromField(x).slice(0, 3);
        return arr.some((v) => !isNaN(new Date(v).getTime()));
      }) || null
    );
  };

  const pickValueField = (series, preferredNames = []) => {
    if (!series?.fields) return null;

    const prefs = preferredNames.map((s) => String(s).toLowerCase());

    for (const nm of prefs) {
      const f = series.fields.find((x) => String(x.name).toLowerCase() === nm);
      if (f) return f;
    }

    const common = ["_value", "value", "val"];
    for (const nm of common) {
      const f = series.fields.find((x) => String(x.name).toLowerCase() === nm);
      if (f) return f;
    }

    return (
      series.fields.find((x) => {
        if (x.type === "time") return false;
        const arr = getArrayFromField(x).slice(0, 10).map(Number);
        return arr.filter(Number.isFinite).length >= 1;
      }) || null
    );
  };

  function fmtHHMM(v) {
    const d = new Date(v);
    if (isNaN(d.getTime())) return "--";
    return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
  }

  function getBatchTrendRows(seriesInput, batchNo, valueField, minField, maxField) {
    const seriesArr = Array.isArray(seriesInput)
      ? seriesInput
      : (seriesInput ? [seriesInput] : []);

    if (!seriesArr.length || !batchNo) {
      return { times: [], values: [], lo: [], hi: [] };
    }

    const outT = [];
    const outV = [];
    const outLo = [];
    const outHi = [];

    for (const series of seriesArr) {
      if (!series?.fields?.length) continue;

      const timeField = pickTimeField(series);
      const valueF = getFieldFromSeries(series, valueField);
      const minF = getFieldFromSeries(series, minField);
      const maxF = getFieldFromSeries(series, maxField);

      const times = getArrayFromField(timeField);
      const values = getArrayFromField(valueF);
      const lo = getArrayFromField(minF);
      const hi = getArrayFromField(maxF);

      const batchField = getFieldFromSeries(series, "batchNo");
      let batches = getArrayFromField(batchField);

      if (!batches.length) {
        const frameBatch = safeStr(getLabelValue(series, "batchNo", ""), "");
        if (frameBatch) {
          batches = Array(times.length).fill(frameBatch);
        }
      }

      const N = Math.min(times.length, batches.length, values.length, lo.length, hi.length);

      for (let i = 0; i < N; i++) {
        if (String(batches[i] || "") !== String(batchNo)) continue;

        const t = times[i];
        const v = Number(values[i]);
        const l = Number(lo[i]);
        const h = Number(hi[i]);

        if (!Number.isFinite(new Date(t).getTime())) continue;
        if (!Number.isFinite(v) || !Number.isFinite(l) || !Number.isFinite(h)) continue;

        outT.push(t);
        outV.push(v);
        outLo.push(l);
        outHi.push(h);
      }
    }

    const zipped = outT.map((t, i) => ({
      t,
      v: outV[i],
      lo: outLo[i],
      hi: outHi[i],
      ts: new Date(t).getTime()
    }))
    .filter(x => Number.isFinite(x.ts))
    .sort((a, b) => a.ts - b.ts);

    return {
      times: zipped.map(x => x.t),
      values: zipped.map(x => x.v),
      lo: zipped.map(x => x.lo),
      hi: zipped.map(x => x.hi),
    };
  }

  function getHistoryRows(series) {
    if (!series?.fields?.length) return [];

    const timeField = pickTimeField(series);
    const batchField = getFieldFromSeries(series, "batchNo");
    const cnTypeField = getFieldFromSeries(series, "cnType");
    const mraTypeField = getFieldFromSeries(series, "mraType");
    const cnField = getFieldFromSeries(series, "cn_current");
    const cnMinField = getFieldFromSeries(series, "cn_min");
    const cnMaxField = getFieldFromSeries(series, "cn_max");
    const nobelField = getFieldFromSeries(series, "nobel_current");
    const nobelMinField = getFieldFromSeries(series, "nobel_min");
    const nobelMaxField = getFieldFromSeries(series, "nobel_max");
    const phField = getFieldFromSeries(series, "ph_current");
    const phMinField = getFieldFromSeries(series, "ph_min");
    const phMaxField = getFieldFromSeries(series, "ph_max");

    const times = getArrayFromField(timeField);
    const batches = getArrayFromField(batchField);
    const cnTypes = getArrayFromField(cnTypeField);
    const mraTypes = getArrayFromField(mraTypeField);
    const cns = getArrayFromField(cnField).map(Number);
    const cnMins = getArrayFromField(cnMinField).map(Number);
    const cnMaxs = getArrayFromField(cnMaxField).map(Number);
    const nobels = getArrayFromField(nobelField).map(Number);
    const nobelMins = getArrayFromField(nobelMinField).map(Number);
    const nobelMaxs = getArrayFromField(nobelMaxField).map(Number);
    const phs = getArrayFromField(phField).map(Number);
    const phMins = getArrayFromField(phMinField).map(Number);
    const phMaxs = getArrayFromField(phMaxField).map(Number);

    const N = Math.max(
      times.length, batches.length, cnTypes.length, mraTypes.length,
      cns.length, cnMins.length, cnMaxs.length,
      nobels.length, nobelMins.length, nobelMaxs.length,
      phs.length, phMins.length, phMaxs.length
    );

    const out = [];
    for (let i = 0; i < N; i++) {
      out.push({
        time: times[i] ?? null,
        batch: safeStr(batches[i], "--"),
        cnType: safeStr(cnTypes[i], "--"),
        mraType: safeStr(mraTypes[i], "--"),
        cn: safeNum(cns[i], NaN),
        cnMin: safeNum(cnMins[i], NaN),
        cnMax: safeNum(cnMaxs[i], NaN),
        nobel: safeNum(nobels[i], NaN),
        nobelMin: safeNum(nobelMins[i], NaN),
        nobelMax: safeNum(nobelMaxs[i], NaN),
        ph: safeNum(phs[i], NaN),
        phMin: safeNum(phMins[i], NaN),
        phMax: safeNum(phMaxs[i], NaN),
      });
    }

    return out.filter((r) => r.batch !== "--");
  }

  function isWithinRange(current, min, max) {
    if (!Number.isFinite(current) || !Number.isFinite(min) || !Number.isFinite(max)) return true;
    const lo = Math.min(min, max);
    const hi = Math.max(min, max);
    const EPS = 1e-6;
    return current >= (lo - EPS) && current <= (hi + EPS);
  }

  function setCardStateByValue(valueSelector, ok, forceGrey = false) {
    const valueEl = root.querySelector(valueSelector);
    const card = valueEl ? valueEl.closest(".kpi-card") : null;
    if (!card) return;

    card.classList.remove("kpi-green", "kpi-red", "kpi-grey");

    if (forceGrey) {
      card.classList.add("kpi-grey");
      return;
    }

    card.classList.add(ok ? "kpi-green" : "kpi-red");
  }

  function renderSinglePoint(el, value, min, max, lastEl, unit = "", labels = { value: "Actual", min: "Min", max: "Max" }, timeVal = null, yAxisLabel = String(unit || "").trim()) {
    if (!el) return;

    const W = el.clientWidth || 560;
    const H = el.clientHeight || 150;
    if (W < 50 || H < 50) {
      el.innerHTML = "";
      return;
    }

    const padL = 60, padR = 18, padT = 28, padB = 38;
    const innerH = H - padT - padB;

    let yMin = Math.min(value, min, max);
    let yMax = Math.max(value, min, max);

    if (!Number.isFinite(yMin) || !Number.isFinite(yMax)) {
      el.innerHTML = "";
      return;
    }

    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }

    const pad = (yMax - yMin) * 0.08;
    yMin -= pad;
    yMax += pad;

    const y = (val) => padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;

    const x1 = padL;
    const x2 = W - padR;

    if (lastEl) lastEl.textContent = Number.isFinite(value) ? `${value.toFixed(2)}${unit}` : "--";

    const ticks = 4;
    const yTicks = Array.from({ length: ticks + 1 }, (_, k) => yMin + (k / ticks) * (yMax - yMin));

    const timeLabel = (() => {
      const d = timeVal ? new Date(timeVal) : new Date();
      return isNaN(d.getTime())
        ? "--:--"
        : d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    })();

    const yCurrent = y(value);
    const yLo = y(min);
    const yHi = y(max);

    const clampY = (yy) => Math.max(padT + 10, Math.min(H - padB - 8, yy));
    const labelX = padL + 10;

    el.innerHTML = `
      <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
        <text class="axis-unit" x="${padL}" y="17" text-anchor="start">${yAxisLabel}</text>
        ${yTicks.map((tv) => {
          const yy = y(tv);
          return `
            <line x1="${padL}" y1="${yy}" x2="${W - padR}" y2="${yy}" stroke="rgba(255,255,255,0.08)" stroke-width="1"/>
            <text x="${padL - 8}" y="${yy + 4}" text-anchor="end" fill="rgba(210,225,245,0.78)" font-size="10" font-weight="700">
              ${tv.toFixed(2)}
            </text>
          `;
        }).join("")}
        <line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="rgba(255,255,255,0.10)" stroke-width="1"/>
        <text x="${(padL + W - padR) / 2}" y="${H - 18}" text-anchor="middle" fill="rgba(210,225,245,0.78)" font-size="10" font-weight="700">
          ${timeLabel}
        </text>
        <line x1="${x1}" y1="${yHi}" x2="${x2}" y2="${yHi}" stroke="rgba(125,196,255,0.82)" stroke-width="1.8" stroke-dasharray="5 4"/>
        <line x1="${x1}" y1="${yLo}" x2="${x2}" y2="${yLo}" stroke="rgba(125,196,255,0.82)" stroke-width="1.8" stroke-dasharray="5 4"/>
        <line x1="${x1}" y1="${yCurrent}" x2="${x2}" y2="${yCurrent}" stroke="rgba(88,166,255,0.95)" stroke-width="2.4"/>
        <circle cx="${W - padR - 18}" cy="${yCurrent}" r="4" fill="rgba(88,166,255,0.95)"/>
        <text x="${W - padR - 24}" y="${yCurrent - 8}" text-anchor="end" fill="rgba(240,247,255,0.96)" font-size="10" font-weight="900">
          ${Number(value).toFixed(2)}${unit}
        </text>
        <text x="${labelX}" y="${clampY(yCurrent + 2)}" fill="rgba(88,166,255,0.95)" font-size="10" font-weight="900">${labels.value}</text>
        <text x="${labelX}" y="${clampY(yLo - 4)}" fill="rgba(125,196,255,0.82)" font-size="10" font-weight="900">${labels.min}</text>
        <text x="${labelX}" y="${clampY(yHi - 6)}" fill="rgba(125,196,255,0.82)" font-size="10" font-weight="900">${labels.max}</text>
        <text class="axis-time" x="${(padL + W - padR) / 2}" y="${H - 4}" text-anchor="middle">Time</text>
      </svg>
    `;
  }

  function renderMiniTrendWithAxis({ el, times = [], value = [], min = [], max = [], lastEl, unit = "", yAxisLabel = String(unit || "").trim(), labels = { value: "Actual", min: "Min", max: "Max" }, useLimitsAsAxis = true }) {
    if (!el) return;

    const N = Math.min(value.length, min.length, max.length, times.length);

    if (N === 1) {
      return renderSinglePoint(el, Number(value[0]), Number(min[0]), Number(max[0]), lastEl, unit, labels, times[0], yAxisLabel);
    }

    if (N < 2) {
      el.innerHTML = "";
      return;
    }

    const rows = times.slice(0, N).map((t, i) => ({
      t: new Date(t).getTime(),
      v: Number(value[i]),
      lo: Number(min[i]),
      hi: Number(max[i])
    }))
    .filter(r => Number.isFinite(r.t) && Number.isFinite(r.v))
    .sort((a, b) => a.t - b.t);

    const tArr = rows.map(r => r.t);
    const vArr = rows.map(r => r.v);
    const loArr = rows.map(r => r.lo);
    const hiArr = rows.map(r => r.hi);

    const W = el.clientWidth || 560;
    const H = el.clientHeight || 150;
    if (W < 50 || H < 50) {
      el.innerHTML = "";
      return;
    }

    const padL = 60, padR = 18, padT = 28, padB = 38;
    const innerW = W - padL - padR;
    const innerH = H - padT - padB;

    const loFinite = loArr.filter(Number.isFinite);
    const hiFinite = hiArr.filter(Number.isFinite);
    const vFinite = vArr.filter(Number.isFinite);

    let yMin, yMax;
    if (useLimitsAsAxis && loFinite.length && hiFinite.length) {
      yMin = Math.min(...loFinite, ...vFinite);
      yMax = Math.max(...hiFinite, ...vFinite);
    } else {
      const all = [...vFinite, ...loFinite, ...hiFinite].filter(Number.isFinite);
      if (!all.length) {
        el.innerHTML = "";
        return;
      }
      yMin = Math.min(...all);
      yMax = Math.max(...all);
    }

    if (yMin === yMax) {
      yMin -= 1;
      yMax += 1;
    }

    const pad = (yMax - yMin) * 0.06;
    yMin -= pad;
    yMax += pad;

    const x = (i) => padL + (i / (N - 1)) * innerW;
    const y = (val) => padT + (1 - (val - yMin) / (yMax - yMin)) * innerH;

    const fmtTime = (t) => {
      const d = new Date(t);
      if (isNaN(d.getTime())) return String(t);
      return d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
    };

    const buildPath = (arr) => {
      let d = "";
      for (let i = 0; i < N; i++) {
        const vv = Number(arr[i]);
        if (!Number.isFinite(vv)) continue;
        d += (d ? " L " : "M ") + `${x(i).toFixed(2)} ${y(vv).toFixed(2)}`;
      }
      return d;
    };

    const ticks = 4;
    const yTicks = Array.from({ length: ticks + 1 }, (_, k) => yMin + (k / ticks) * (yMax - yMin));
    const xIdx = [0, Math.floor((N - 1) / 2), N - 1];

    const lastVal = vArr[N - 1];
    if (lastEl) lastEl.textContent = Number.isFinite(lastVal) ? `${lastVal.toFixed(2)}${unit}` : "--";

    const pathVal = buildPath(vArr);
    const pathMin = buildPath(loArr);
    const pathMax = buildPath(hiArr);

    const li = Math.min(1, N - 1);
    const clampY = (yy) => Math.max(padT + 12, Math.min(H - padB - 10, yy));
    const labelX = padL + 10;

    const yMaxLbl = clampY(y(hiArr[li]) - 6);
    const yMinLbl = clampY(y(loArr[li]) - 4);
    const yValLbl = clampY(y(vArr[li]) + 2);

    const lx = x(N - 1);
    const ly = y(lastVal);

    const COLOR_ACTUAL = "rgba(88,166,255,0.95)";
    const COLOR_MINMAX = "rgba(125,196,255,0.82)";
    const COLOR_GRID = "rgba(255,255,255,0.08)";
    const COLOR_AXIS = "rgba(255,255,255,0.10)";
    const COLOR_TEXT = "rgba(210,225,245,0.78)";
    const COLOR_LASTTX = "rgba(240,247,255,0.96)";

    el.innerHTML = `
      <svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg">
        <text class="axis-unit" x="${padL}" y="17" text-anchor="start">${yAxisLabel}</text>
        ${yTicks.map((tv) => {
          const yy = y(tv);
          return `
            <line x1="${padL}" y1="${yy}" x2="${W - padR}" y2="${yy}" stroke="${COLOR_GRID}" stroke-width="1"/>
            <text x="${padL - 8}" y="${yy + 4}" text-anchor="end" fill="${COLOR_TEXT}" font-size="10" font-weight="700">
              ${tv.toFixed(2)}
            </text>
          `;
        }).join("")}
        <line x1="${padL}" y1="${H - padB}" x2="${W - padR}" y2="${H - padB}" stroke="${COLOR_AXIS}" stroke-width="1"/>
        ${xIdx.map((i) => `
          <text x="${x(i)}" y="${H - 18}" text-anchor="middle" fill="${COLOR_TEXT}" font-size="10" font-weight="700">
            ${fmtTime(tArr[i])}
          </text>
        `).join("")}
        <path d="${pathMin}" fill="none" stroke="${COLOR_MINMAX}" stroke-width="1.7" stroke-dasharray="5 4"></path>
        <path d="${pathMax}" fill="none" stroke="${COLOR_MINMAX}" stroke-width="1.7" stroke-dasharray="5 4"></path>
        <path d="${pathVal}" fill="none" stroke="${COLOR_ACTUAL}" stroke-width="2.4"></path>

        <text x="${labelX}" y="${yMinLbl}" fill="${COLOR_MINMAX}" font-size="10" font-weight="900">${labels.min}</text>
        <text x="${labelX}" y="${yMaxLbl}" fill="${COLOR_MINMAX}" font-size="10" font-weight="900">${labels.max}</text>
        ${
          Number.isFinite(lastVal)
            ? `
          <circle cx="${lx}" cy="${ly}" r="3.3" fill="${COLOR_ACTUAL}"/>
          <text x="${lx - 6}" y="${ly - 8}" text-anchor="end" fill="${COLOR_LASTTX}" font-size="10" font-weight="900">
            ${lastVal.toFixed(2)}${unit}
          </text>
        `
            : ""
        }
        <line class="hover-line" x1="0" y1="${padT}" x2="0" y2="${H-padB}"
              stroke="rgba(255,255,255,0.35)" stroke-width="1"
              stroke-dasharray="4 4" style="display:none"/>

        <circle class="hover-dot" cx="0" cy="0" r="4"
                fill="${COLOR_ACTUAL}" stroke="#fff" stroke-width="1.5"
                style="display:none"/>

        <g class="hover-tip" style="display:none">
          <filter id="tooltipShadow" x="-20%" y="-20%" width="140%" height="140%">
            <feDropShadow dx="0" dy="3" stdDeviation="4" flood-color="#000000" flood-opacity="0.75"/>
          </filter>

          <rect width="172" height="76" rx="10"
                fill="rgba(8,18,34,0.98)"
                stroke="rgba(88,166,255,0.95)"
                stroke-width="1"
                filter="url(#tooltipShadow)"/>

          <rect width="172" height="31" rx="10"
                fill="rgba(25,85,150,0.85)"/>

          <text class="hover-time" x="10" y="13" fill="#ffffff" font-size="11" font-weight="600"></text>
          <text class="hover-date" x="10" y="27" fill="#ffffff" font-size="10" font-weight="500"></text>

          <circle cx="13" cy="46" r="4" fill="${COLOR_ACTUAL}"/>

          <text class="hover-val" x="24" y="50" fill="#ffffff" font-size="12" font-weight="800"></text>
          <text class="hover-range" x="10" y="67" fill="#bfe2ff" font-size="10" font-weight="500"></text>
        </g>
        <text class="axis-time" x="${(padL + W - padR) / 2}" y="${H - 4}" text-anchor="middle">Time</text>
      </svg>
    `;

      const svg = el.querySelector("svg");

        if (svg) {
          const hoverLine = svg.querySelector(".hover-line");
          const hoverDot = svg.querySelector(".hover-dot");
          const hoverTip = svg.querySelector(".hover-tip");
          const hoverTime = svg.querySelector(".hover-time");
          const hoverDate = svg.querySelector(".hover-date");
          const hoverVal = svg.querySelector(".hover-val");
          const hoverRange = svg.querySelector(".hover-range");

          svg.addEventListener("mousemove", (e) => {
            const rect = svg.getBoundingClientRect();
            const mx = ((e.clientX - rect.left) / rect.width) * W;

            let idx = Math.round(((mx - padL) / innerW) * (N - 1));
            idx = Math.max(0, Math.min(N - 1, idx));

            const val = Number(vArr[idx]);
            const lo = Number(loArr[idx]);
            const hi = Number(hiArr[idx]);
            if (!Number.isFinite(val)) return;

            const px = x(idx);
            const py = y(val);

            hoverLine.setAttribute("x1", px);
            hoverLine.setAttribute("x2", px);
            hoverLine.style.display = "";

            hoverDot.setAttribute("cx", px);
            hoverDot.setAttribute("cy", py);
            hoverDot.style.display = "";

            const TIP_W = 172;
            const TIP_H = 76;

            let tipX = px + 10;
            let tipY = py - 76;

            if (tipX + TIP_W > W - 5) tipX = px - TIP_W - 10;
            if (tipY < padT + 5) tipY = py + 14;
            if (tipY + TIP_H > H - padB) tipY = H - padB - TIP_H - 5;

            hoverTip.setAttribute("transform", `translate(${tipX},${tipY})`);
            hoverTip.style.display = "";

            const dt = new Date(tArr[idx]);

            hoverTime.textContent = fmtTime(tArr[idx]);
            hoverDate.textContent = dt.toLocaleDateString("en-GB", {
              day: "2-digit",
              month: "short",
              year: "numeric"
            });

            hoverVal.textContent = `${labels.value}: ${val.toFixed(2)}${unit}`;
            hoverRange.textContent =
              `Min ${Number.isFinite(lo) ? lo.toFixed(2) : "--"}  Max ${Number.isFinite(hi) ? hi.toFixed(2) : "--"}`;
          });

          svg.addEventListener("mouseleave", () => {
            hoverLine.style.display = "none";
            hoverDot.style.display = "none";
            hoverTip.style.display = "none";
          });
        }


    }

