      const vf = pickValueField(lvlSeries, ["level", "level_cm", "lvl"]);
      t = getArrayFromField(tf);
      v = getArrayFromField(vf).map(Number);
    }

    const N = Math.min(t.length, v.length);
    const lo = Array.from({ length: N }, () => 0);
    const hi = Array.from({ length: N }, () => MAX_LEVEL);

    if (N >= 1) {
      defer(() =>
        renderMiniTrendWithAxis({
          el: root.querySelector("#lvlChart"),
          times: t,
          value: v,
          min: lo,
          max: hi,
          lastEl: root.querySelector("#lvlLast"),
          unit: "",
          yAxisLabel: "cm",
          labels: { value: "Level", min: "Min 0", max: "Max 340" },
          useLimitsAsAxis: true,
        })
      );
    } else {
      clearChart("#lvlChart", "#lvlLast");
    }

    const lastLevel = safeNum(v?.[0], NaN);
    setText("#levelCm", Number.isFinite(lastLevel) ? lastLevel.toFixed(0) : "--");

    const tankFill = root.querySelector("#tankFill");
    if (tankFill) {
      if (Number.isFinite(lastLevel)) {
        const clamped = Math.max(0, Math.min(MAX_LEVEL, lastLevel));
        tankFill.style.height = ((clamped / MAX_LEVEL) * 100).toFixed(1) + "%";
        tankFill.classList.remove("level-green", "level-yellow", "level-red");
        const pct = (clamped / MAX_LEVEL) * 100;
        if (pct >= 55) tankFill.classList.add("level-green");
        else if (pct >= 25) tankFill.classList.add("level-yellow");
        else tankFill.classList.add("level-red");
      } else {
        tankFill.style.height = "0%";
        tankFill.classList.remove("level-green", "level-yellow", "level-red");
      }
    }
  }

  const timeStr = live.timeVal
    ? isNaN(new Date(live.timeVal))
      ? safeStr(live.timeVal, "--")
      : new Date(live.timeVal).toLocaleString()
    : new Date().toLocaleString();

  setText("#lastUpdate", timeStr);

  const rows = Array.from(root.querySelectorAll(".pcd-item"));
  const search = root.querySelector("#pcdSearchMain");
  const alarmBody = root.querySelector("#alarmBody");
  const alarmBadge = root.querySelector("#alarmBadge");
  const alarmSub = root.querySelector("#alarmSub");
  const alarmSearch = root.querySelector("#alarmSearch");
  const alarmFootL = root.querySelector("#alarmFootLeft");

  function applyFilter() {
    const q = (search?.value || "").toLowerCase().trim();
    rows.forEach((r) => {
      const b = (r.dataset.batch || "").toLowerCase();
      const p = (r.dataset.po || "").toLowerCase();
      r.style.display = !q || b.includes(q) || p.includes(q) ? "" : "none";
    });
  }

  function nowTimeParts() {
    const d = new Date();
    return {
      dt: d.toLocaleDateString(),
      tm: d.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" }),
    };
  }

  function renderAlarms(list) {
    const q = (alarmSearch?.value || "").toLowerCase().trim();
    const filtered = !q
      ? list
      : list.filter(
          (a) =>
            String(a.code || "").toLowerCase().includes(q) ||
            String(a.msg || "").toLowerCase().includes(q) ||
            String(a.sub || "").toLowerCase().includes(q)
        );

    const activeCount = list.filter((a) => String(a.status).toUpperCase() === "ACTIVE").length;
    if (alarmBadge) alarmBadge.textContent = `${activeCount} Active`;

    if (!alarmBody) return;

    if (!filtered.length) {
      alarmBody.innerHTML = `
        <div class="log-row is-clear sev-low">
          <div class="log-time"><div class="dt">--</div><div class="tm">--</div></div>
          <div class="log-code">NO-ALARM</div>
          <div class="log-msg">
            <div class="msg-main">No active alarms</div>
            <div class="msg-sub">Selected tank / batch is within alarm conditions</div>
          </div>
          <div><span class="tag state clear">CLEAR</span></div>
        </div>
      `;
      return;
    }

    alarmBody.innerHTML = filtered
      .map((a) => {
        const sevClass =
          a.severity === "CRITICAL"
            ? "sev-high"
            : a.severity === "WARNING"
            ? "sev-med"
            : a.severity === "INFO"
            ? "sev-info"
            : "sev-low";

        const stateClass =
          String(a.status || "CLEAR").toUpperCase() === "ACTIVE" ? "is-active" : "is-clear";

        return `
          <div class="log-row ${sevClass} ${stateClass}">
            <div class="log-time">
              <div class="dt">${a.dt || "--"}</div>
              <div class="tm">${a.tm || "--"}</div>
            </div>
            <div class="log-code">${a.code || "--"}</div>
            <div class="log-msg">
              <div class="msg-main">${a.msg || "--"}</div>
              <div class="msg-sub">${a.sub || ""}</div>
            </div>
            <div>
              <span class="tag state ${
                String(a.status || "CLEAR").toUpperCase() === "ACTIVE" ? "active" : "clear"
              }">
                ${(a.status || "CLEAR").toUpperCase()}
              </span>
            </div>
          </div>
        `;
      })
      .join("");
  }

  function buildAlarmsForSnapshot(snap) {
    const t = nowTimeParts();
    const out = [];

    const cn = safeNum(snap.cn, NaN);
    const cnMin = safeNum(snap.cnMin, NaN);
    const cnMax = safeNum(snap.cnMax, NaN);

    const nobel = safeNum(snap.nobel, NaN);
    const nobelMin = safeNum(snap.nobelMin, NaN);
    const nobelMax = safeNum(snap.nobelMax, NaN);

    const ph = safeNum(snap.ph, NaN);
    const phMin = safeNum(snap.phMin, NaN);
    const phMax = safeNum(snap.phMax, NaN);

    const level = safeNum(snap.level, NaN);

    if (Number.isFinite(cn) && Number.isFinite(cnMin) && Number.isFinite(cnMax) && !isWithinRange(cn, cnMin, cnMax)) {
      out.push({ dt: t.dt, tm: t.tm, code: "CN-OOR", msg: "CN out of range", status: "ACTIVE", severity: "CRITICAL" });
    }

    if (Number.isFinite(nobel) && Number.isFinite(nobelMin) && Number.isFinite(nobelMax) && !isWithinRange(nobel, nobelMin, nobelMax)) {
      out.push({ dt: t.dt, tm: t.tm, code: "NOBEL-OOR", msg: "Nobel out of range", status: "ACTIVE", severity: "CRITICAL" });
    }

    if (Number.isFinite(ph) && Number.isFinite(phMin) && Number.isFinite(phMax) && !isWithinRange(ph, phMin, phMax)) {
      out.push({ dt: t.dt, tm: t.tm, code: "PH-OOR", msg: "pH out of range", status: "ACTIVE", severity: "CRITICAL" });
    }

    if (Number.isFinite(level) && level < 100) {
      out.push({ dt: t.dt, tm: t.tm, code: "LEVEL-LOW", msg: "Tank level low", status: "ACTIVE", severity: "WARNING" });
    }

    if (!out.length) {
      out.push({ dt: t.dt, tm: t.tm, code: "STABLE", msg: "No active alarms", status: "CLEAR", severity: "INFO" });
    }

    return out;
  }

  function setSelected(btn) {
    root.querySelectorAll(".pcd-state-btn").forEach((b) => b.classList.remove("is-selected"));
    if (btn) btn.classList.add("is-selected");
  }

  function fillHistoryRow(rowEl, item, stateText) {
    if (!rowEl) return;

    const cells = rowEl.querySelectorAll(":scope > div");
    const btn = rowEl.querySelector(".pcd-state-btn");

    const batch = item?.batch || "--";
    const cnType = item?.cnType || "--";
    const mraType = item?.mraType || "--";
    const cn = Number.isFinite(item?.cn) ? item.cn.toFixed(2) + "%" : "--";
    const ph = Number.isFinite(item?.ph) ? item.ph.toFixed(2) : "--";
    const start = item?.time ? fmtHHMM(item.time) : "--";
    const end = stateText === "COMPLETED" ? (item?.time ? fmtHHMM(item.time) : "--") : "--";
    const duration = stateText === "COMPLETED" ? "Done" : "Running";

    rowEl.setAttribute("data-batch", batch);
    rowEl.setAttribute("data-po", cnType);

    if (cells[0]) cells[0].textContent = batch;
    if (cells[1]) cells[1].textContent = cnType;
    if (cells[2]) cells[2].textContent = mraType;
    if (cells[3]) cells[3].innerHTML = `<span class="pcd-chipval">${cn}</span>`;
    if (cells[4]) cells[4].innerHTML = `<span class="pcd-chipval ph">${ph}</span>`;
    if (cells[5]) cells[5].textContent = start;
    if (cells[6]) cells[6].textContent = end;
    if (cells[7]) cells[7].textContent = duration;

    if (btn) {
      btn.textContent = stateText;
      btn.dataset.state = stateText;
      btn.dataset.tank = currentTank;
      btn.dataset.batch = batch;
      btn.dataset.cnType = cnType;
      btn.dataset.mraType = mraType;
      btn.dataset.cn = Number.isFinite(item?.cn) ? item.cn : "";
      btn.dataset.cnmin = Number.isFinite(item?.cnMin) ? item.cnMin : "";
      btn.dataset.cnmax = Number.isFinite(item?.cnMax) ? item.cnMax : "";
      btn.dataset.nobel = Number.isFinite(item?.nobel) ? item.nobel : "";
      btn.dataset.nobelmin = Number.isFinite(item?.nobelMin) ? item.nobelMin : "";
      btn.dataset.nobelmax = Number.isFinite(item?.nobelMax) ? item.nobelMax : "";
      btn.dataset.ph = Number.isFinite(item?.ph) ? item.ph : "";
      btn.dataset.phmin = Number.isFinite(item?.phMin) ? item.phMin : "";
      btn.dataset.phmax = Number.isFinite(item?.phMax) ? item.phMax : "";
      btn.classList.remove("running", "completed");
      btn.classList.add(stateText.toLowerCase());

      if (batch === "--") {
        btn.style.opacity = "0.45";
        btn.style.pointerEvents = "none";
        btn.style.cursor = "not-allowed";
      } else {
        btn.style.opacity = "1";
        btn.style.pointerEvents = "auto";
        btn.style.cursor = "pointer";
      }
    }
  }

  const historyRows = getHistoryRows(historySeries);
  const runningRow = historyRows[0] || null;
  const completedRow = historyRows[1] || null;

  fillHistoryRow(rows[0], runningRow, "RUNNING");
  fillHistoryRow(rows[1], completedRow, "COMPLETED");
  applyFilter();

  function handleStateButtonClick(btn) {
    if (!btn || !btn.dataset.batch || btn.dataset.batch === "--") return;

    setSelected(btn);

    const mode = String(btn.dataset.state || "RUNNING").toUpperCase();

    const currentLevel = safeNum(
      getFirst(lvlSeries, "level", getFirst(lvlSeries, "level_cm", getFirst(lvlSeries, "lvl", NaN))),
      NaN
    );

    const snap = {
      mode,
      tank: btn.dataset.tank || currentTank,
      batch: btn.dataset.batch || "--",
      cnType: btn.dataset.cnType || "--",
      mraType: btn.dataset.mraType || "--",
      cn: safeNum(btn.dataset.cn, live.cn),
      cnMin: safeNum(btn.dataset.cnmin, live.cnMin),
      cnMax: safeNum(btn.dataset.cnmax, live.cnMax),
      nobel: safeNum(btn.dataset.nobel, live.nobel),
      nobelMin: safeNum(btn.dataset.nobelmin, live.nobelMin),
      nobelMax: safeNum(btn.dataset.nobelmax, live.nobelMax),
      ph: safeNum(btn.dataset.ph, live.ph),
      phMin: safeNum(btn.dataset.phmin, live.phMin),
      phMax: safeNum(btn.dataset.phmax, live.phMax),
      hz: live.hz,
      level: currentLevel,
    };

    applyKPI({
      cnType: snap.cnType,
      mraType: snap.mraType,
      cn: snap.cn,
      cnMin: snap.cnMin,
      cnMax: snap.cnMax,
      nobel: snap.nobel,
      nobelMin: snap.nobelMin,
      nobelMax: snap.nobelMax,
      ph: snap.ph,
      phMin: snap.phMin,
      phMax: snap.phMax,
      hz: snap.hz,
    });

    if (mode === "COMPLETED") {
      renderSelectedBatchCharts(snap.batch);
    } else {
      renderRunningCharts();
    }

    const alarmList = buildAlarmsForSnapshot(snap);

    if (alarmSub) alarmSub.textContent = `${mode} • ${snap.batch} • CT${snap.tank}`;
    if (alarmFootL) alarmFootL.textContent = `Last refresh: ${new Date().toLocaleString()}`;

    renderAlarms(alarmList);
  }

  root.__handleStateButtonClick = handleStateButtonClick;

  if (!root.__ct_bound) {
    root.__ct_bound = true;

    if (search) search.addEventListener("input", applyFilter);

    root.addEventListener("click", (e) => {
      const btn = e.target.closest(".pcd-state-btn");
      if (!btn) return;
      if (typeof root.__handleStateButtonClick === "function") {
        root.__handleStateButtonClick(btn);
      }
    });

    if (alarmSearch) {
      alarmSearch.addEventListener("input", () => {
        const sel = root.querySelector(".pcd-state-btn.is-selected");
        if (sel && typeof root.__handleStateButtonClick === "function") {
          root.__handleStateButtonClick(sel);
        }
      });
    }
  }

  defer(() => {
    const defaultBtn =
      root.querySelector(".pcd-state-btn.running") ||
      root.querySelector(".pcd-state-btn.completed");

    if (defaultBtn && typeof root.__handleStateButtonClick === "function") {
      root.__handleStateButtonClick(defaultBtn);
    } else {
      const currentLevel = safeNum(
        getFirst(lvlSeries, "level", getFirst(lvlSeries, "level_cm", getFirst(lvlSeries, "lvl", NaN))),
        NaN
      );

      const alarmList = buildAlarmsForSnapshot({
        mode: "RUNNING",
        tank: currentTank,
        batch: live.batch,
        cnType: live.cnType,
        mraType: live.mraType,
        cn: live.cn,
        cnMin: live.cnMin,
        cnMax: live.cnMax,
        nobel: live.nobel,
        nobelMin: live.nobelMin,
        nobelMax: live.nobelMax,
        ph: live.ph,
        phMin: live.phMin,
        phMax: live.phMax,
        hz: live.hz,
        level: currentLevel,
      });

      renderAlarms(alarmList);
      if (alarmSub) alarmSub.textContent = `RUNNING • ${live.batch} • CT${currentTank}`;
      if (alarmFootL) alarmFootL.textContent = `Last refresh: ${new Date().toLocaleString()}`;
    }
  });

} catch (e) {
  console.log("CT Dashboard OnRender error:", e);
}
